      "path": "src/modules/tasks/service.js",
      "content": "const projectsService = require('../projects/service');
const { randomUUID } = require('node:crypto');

function getTasks(projectId, status) {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  let tasks = project.tasks;
  if (status) {
    tasks = tasks.filter(task => task.status === status);
  }
  return tasks;
}

function createTask(projectId) {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const taskId = randomUUID();
  const task = { id: taskId, status: 'todo' };
  project.tasks.push(task);
  return task;
}

function updateTask(projectId, taskId, status) {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  if (status !== 'todo' && status !== 'done') {
    return null;
  }
  task.status = status;
  return task;
}

module.exports = {
  getTasks,
  createTask,
  updateTask,
};
